import{Bench}from"tinybench";import{scaleLinear}from"d3-scale";import globals from"../globals.mjs";import{IntervalWorkerPool,BackpressureStrategy}from"../samplers/interval_worker_pool.js";import{createPathD}from"../graph-types/interval.js";import{asyncSamplerInterval,syncSamplerInterval}from"../samplers/interval.js";async function createData(a,e,n){var t=[-5,5],r=scaleLinear().domain(t).range([0,500]),o=scaleLinear().domain([-5,5]).range([300,0]),t={d:{fn:"1/x",fnType:"linear",index:1},range:t,xScale:r,yScale:o,xAxis:{type:"linear"},yAxis:{type:"linear"},nSamples:a,nGroups:e};let l;return{data:l=n?await asyncSamplerInterval(t):syncSamplerInterval(t),xScale:r,yScale:o}}async function compileAndEval(){var a=[4,8,12];for(const e of[350,750,1800,3600]){const n=new Bench;for(const t of a)n.add(`nSamples=${e} nGroups=${t} compile and eval sync`,async function(){await createData(e,t,!1)}),n.add(`nSamples=${e} nGroups=${t} compile and eval async`,async function(){await createData(e,t,!0)});await n.run(),console.table(n.table())}}async function consecutiveEval(){const a=new Bench;for(const n of[BackpressureStrategy.InvalidateSeenLimit,BackpressureStrategy.InvalidateSeenScan,BackpressureStrategy.None,BackpressureStrategy.InvalidateSeenMap])a.add(`nSamples=1000 nGroups=16 iterations=64 backpressure=${n} consecutive eval`,async function(){globals.workerPool.setBackpressure(n);const e=[];for(let a=0;a<64;a+=1)e.push(createData(1e3,16,!0));await Promise.all(e)});await a.run(),console.table(a.table())}async function drawPath(){const a=new Bench;const{xScale:e,yScale:n,data:t}=await createData(1e3,4,!1);a.add("drawPath 1000",function(){createPathD(e,n,1,t[0],!1)}),await a.run(),console.table(a.table())}async function main(){globals.workerPool=new IntervalWorkerPool(8),await compileAndEval(),await consecutiveEval(),await drawPath(),await globals.workerPool.terminate()}main();